class Solution:
    def longestOnes(self, nums,k):
      # maxlen=0
      # for i in range(len(nums)):
      #   zeros=0
      #   for j in range(i,len(nums)):
      #     if nums[j] == 0:
      #       zeros+=1
      #     if zeros<=k:
      #       length=j-i+1
      #       maxlen=max(maxlen,length)
      #     else:
      #       break
      # return maxlen
      maxlen,r,l,zeros=0,0,0,0
      while(r < len(nums)):
        if(nums[r]==0):
          zeros+=1
        while(zeros > k):
          if nums[l] == 0:
            zeros-=1
          l+=1
        maxlen=max(maxlen,r-l+1)
        r+=1
      return maxlen
      

